import React, { useState } from 'react';
import './css/addofficer.css'; // Import the CSS file

const AddOfficer = () => {
  const [name, setName] = useState('');
  const [role, setRole] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(null); // State to handle errors
  const [success, setSuccess] = useState(null); // State to handle success messages

  const handleSubmit = async (e) => {
    e.preventDefault();

    const officerData = { name, role, email, password };

    try {
      const response = await fetch('http://localhost:8088/api/auth/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(officerData),
      });

      if (!response.ok) {
        const data = await response.json();
        setError(data.message || 'Failed to add officer'); // Handle error messages from the API
        setSuccess(null);
      } else {
        setSuccess('Officer added successfully!');
        setError(null);
        
        // Reset the form after successful submission
        setName('');
        setRole('');
        setEmail('');
        setPassword('');
      }
    } catch (error) {
      setError('An error occurred while adding the officer.');
      setSuccess(null);
    }
  };

  return (
    <div className="add-officer">
      <h2 className="h2">Add Officer</h2>
      {error && <div className="error">{error}</div>} {/* Display error message */}
      {success && <div className="success">{success}</div>} {/* Display success message */}
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Name:</label>
          <input
            type="text"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
          />
        </div>
        <div className="form-group">
          <label>Role:</label>
          <select
            value={role}
            onChange={(e) => setRole(e.target.value)}
            required
          >
            <option value="" disabled>Select a role</option>
            <option value="ADMIN">Admin</option>
            <option value="ACCOUNTANT">Account Officer</option>
            <option value="CLERK">Clerk</option>
          </select>
        </div>
        <div className="form-group">
          <label>Email:</label>
          <input
            type="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
          />
        </div>
        <div className="form-group">
          <label>Password:</label>
          <input
            type="password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            required
          />
        </div>
        <button type="submit">Add Officer</button>
      </form>
    </div>
  );
};

export default AddOfficer;
